class Solution {
    public int longestDecomposition(String text) {
        int n = text.length();
        for (int i = 1; i <= n / 2; i++) {
            if (n % i == 0) {
                String prefix = text.substring(0, i);
                boolean ok = true;
                for (int j = i; j < n; j += i) {
                    if (!text.substring(j, j + i).equals(prefix)) {
                        ok = false;
                        break;
                    }
                }
                if (ok) {
                    return n / i;
                }
            }
        }
        return 1;
    }
}
